var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"시공간 수정의 후유증은 꽤나 다양해, 친구.","JPN":"時空間修正の後遺症は、かなり様々だ。","ENG":"Side effects of spacetime recalibration are quite diverse, my friend.","TWN":"修正時空會引起多種後遺症，朋友。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"특히나 자네처럼 많이 겪은 경우에는...... 무슨 일이 일어날지 장담할 수 없어.","JPN":"特に君のように、色んなことがあった場合……何が起きるかわからない。","ENG":"And for someone who has done it multiple times like yourself, there's no telling what might happen.","TWN":"特別是像你這種經歷了很多次的情況……我無法保證會發生什麼。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 자네의 길잡이로서, 이것 하나는 얘기해 줄 수 있겠군.","JPN":"だが、君のガイドとして、これだけは言える。","ENG":"But as your guide, I can tell you this.","TWN":"但作為你的領路人，我可以告訴你一點。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"꿈에서 다른 사람과 눈을 마주치게 되더라도 너무 놀라진 마. 그건 실제가 아니고, 그들의 추억을 잠시 관측하는 것 뿐이니까.","JPN":"夢の中で他の人と目が合っても、あまり驚くな。それは現実ではなく、彼らの思い出を少し観察するにすぎない。","ENG":"Don't be too surprised if you get to make eye contact with someone else. It's not real. You're observing their memories for a short period of time.","TWN":"在夢裡，即使與他人對上視線也不要太驚訝。因為那並不是現實，你只是在暫時觀看他們的回憶而已。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 사람들의 행복했던 시절을 함께 돌아보는 것도...... 자네가 앞으로 걸을 길에 작은 위안 정도는 되겠지.","JPN":"だが、誰かの幸せだった時期を一緒に振り返るのも……これから君が歩むべき道の、小さな癒しにはなるだろう。","ENG":"But looking back at people's memories of their happy past could provide some comfort for your mind while walking the path you're on.","TWN":"不過，與他人一同觀看幸福的回憶……或許能成為你前進的道路上的小小慰藉。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"와, 날씨가 엄청 좋네. 오늘 소풍 나오길 잘했다. 그치?","JPN":"わあ、今日はすごく天気がいいね。ピクニックに来てよかった。ね？","ENG":"Wow, what a lovely day! Picnic was a good idea, don't you think?","TWN":"哇，天氣真好啊。還好今天出來散步了。對吧？"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YUMI_POLICE_NULL_CHILD","text":{"KOREA":"응! 빵도 맛있는 것들로 잔뜩 담아왔어.","JPN":"うん！　おいしいパンもいっぱい持ってきたよ。","ENG":"Yeah! And I've packed all kinds of bread in the basket.","TWN":"嗯！我帶來了很多好吃的麵包喲。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"앗, 너무 많이 먹으면 안돼. 이따가 엄마가 챙겨준 도시락도 먹어야 하니까.","JPN":"あっ、食べ過ぎちゃだめ。お母さんが作ってくれたお弁当もあるから。","ENG":"Ah, but you'll need to save room for the lunch Mom made us.","TWN":"啊，不要吃太多。待會兒還要吃媽媽做的便當呢。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YUMI_POLICE_NULL_CHILD","text":{"KOREA":"걱정 마. 다 먹을 수 있거든.","JPN":"大丈夫。全部食べられるもん。","ENG":"Don't worry. I can handle that much.","TWN":"別擔心。我都能吃完的。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_TOUCH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"하하......","JPN":"はは……","ENG":"Hah hah...","TWN":"哈哈……"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"있지. 유미는 커서 어른이 되면, 뭘 하고 있을 거 같아?","JPN":"ねえ、ユミは大人になったらどんな仕事をしてるかな？","ENG":"Hey, Yumi. What do you think you want to do when you grow up?","TWN":"那個。悠美長大後，想做什麼呢？"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YUMI_POLICE_NULL_CHILD","text":{"KOREA":"음......","JPN":"うーん……","ENG":"Umm...","TWN":"嗯……"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YUMI_POLICE_NULL_CHILD","text":{"KOREA":"......빵?","JPN":"……パン？","ENG":"Bake bread?","TWN":"……麵包？"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"아하, 제빵사가 되고 싶다는 거지?","JPN":"あ、パン屋さんになりたいの？","ENG":"Ah, you want to be a baker?","TWN":"啊哈，是想當麵包師傅嗎？"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YUMI_POLICE_NULL_CHILD","text":{"KOREA":"과자 만드는 것도 좋아. 언니가 과자 좋아하고, 나도 좋아하니까.","JPN":"お菓子を作るのも好き。お姉ちゃんがお菓子好きだし、私も好きだから。","ENG":"I want to bake cookies as well. You like cookies, and I like cookies.","TWN":"做餅乾也不錯。因為姐姐喜歡吃，所以我也喜歡吃。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"응. 그거 좋겠다.","JPN":"うん、それいいね。","ENG":"Yes, that sounds wonderful.","TWN":"嗯。不錯不錯。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YUMI_POLICE_NULL_CHILD","text":{"KOREA":"......언니는 크면 뭐가 하고 싶은데?","JPN":"……お姉ちゃんは？","ENG":"What do you want to do when you grow up?","TWN":"……姐姐長大後想當什麼呀？"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"음, 글쎄......","JPN":"うーん、どうだろう……","ENG":"Um, I don't know.","TWN":"嗯，我想想……"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"유미가 원하는 꿈을 이룰 수 있게 응원해주는 거?","JPN":"ユミの夢を応援したいな。","ENG":"I could root for you so that you could make your dream come true.","TWN":"為悠美的夢想加油？"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YUMI_POLICE_NULL_CHILD","text":{"KOREA":"그게 뭐야...... 시시해.","JPN":"何それ……つまんない。","ENG":"Huh? That's boring.","TWN":"什麼啊……真無趣。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"하하...... 왜냐면 난 지금 이대로가 좋거든.","JPN":"はは……私は今のままがいいもん。","ENG":"Hah hah... But I like the way things are now.","TWN":"哈哈……因為現在這樣我就很開心了。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"엄마아빠가 함께 있고, 너랑 같이 이렇게 소풍도 다니고......","JPN":"お母さんやお父さんと一緒だし、ユミとこうしてピクニックに来られるから……","ENG":"We have mom and dad, and we get to go on picnics like this.","TWN":"和爸媽在一起，和你在一起，像現在這樣兜兜風……"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"아, 맞아!","JPN":"あ、そうだ！","ENG":"Ah! I know!","TWN":"啊，對了！"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"뭔가를 하게 된다면, 보디가드가 좋겠다!","JPN":"ボディガードになろうかな！","ENG":"A bodyguard would be great!","TWN":"非要做什麼的話，就做個保鏢吧！"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"우리 이유미 제빵사님을 지켜주는 보디가드. 어때?","JPN":"パン屋さんのユミを守ってあげる、ボディガード。どう？","ENG":"I'll be protecting you from harm when you become a baker. How's that?","TWN":"來保護我們的麵包大師李悠美。怎麼樣？"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YUMI_POLICE_NULL_CHILD","text":{"KOREA":"제빵사가 되면...... 그렇게나 위험해져?","JPN":"パン屋さんって……そんなに危険な仕事なの？","ENG":"Bakers have bodyguards? Is it really that dangerous of a job?","TWN":"當麵包師傅……會那麼危險嗎？"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"응? 아냐. 유미 네가 제빵사가 안 되더라도 내 꿈엔 변함이 없어.","JPN":"うん？　違うよ。ユミがパン屋さんにならなくても、私の夢は変わらないわ。","ENG":"Hm? No, honey. My dream will be the same even if you don't become a baker.","TWN":"嗯？不是啊。就算悠美沒當上麵包師，我也不會改變我的夢想。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"난 네가 어떤 선택을 하게 되든, 내가 널 곁에서 응원하고 지켜줄 거라는 뜻이야.","JPN":"ユミがどんな選択をしても、私がそばで守ってあげるってこと。","ENG":"I'm just saying whatever choice you make, I'll be there to root for you and protect you.","TWN":"無論你做出什麼選擇，我都會在你身邊為你加油，保護你。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YUMI_POLICE_NULL_CHILD","text":{"KOREA":"흐음......","JPN":"ふーん……","ENG":"Hmm...","TWN":"哼嗯……"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YUMI_POLICE_NULL_CHILD","text":{"KOREA":"그럼 나도 보디가드 할래! 그래서 언니를 응원하고 지켜줄 거야!","JPN":"じゃあ、私もボディガードになる！　それで、お姉ちゃんのこと応援して守ってあげる！","ENG":"Then I'll be a bodyguard as well. I want to root for you and protect you from harm, too.","TWN":"那我也要當保鏢！我要給姐姐加油，保護姐姐！"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":null,"text":{"KOREA":"아하하, 꿈이 그렇게 쉽게 바뀌면 어떡해.","JPN":"あはは、夢が簡単に変わっちゃったね。","ENG":"Hah hah, but you said you wanted to be a baker just a minute ago.","TWN":"哈哈，怎麼能這麼輕易就改變夢想呢。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"YUMI_POLICE_NULL_CHILD","text":{"KOREA":"바뀐 거 아냐! 나도 언니 지켜줄 수 있어!","JPN":"違うよ！　私もお姉ちゃんのこと、守れるもん！","ENG":"I did. And I'll protect you from harm, too.","TWN":"我沒改變！我也可以保護姐姐！"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":null,"text":{"KOREA":"으응?","JPN":"ん？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":null,"text":{"KOREA":"......하긴 그렇구나.","JPN":"……そうだよね。","ENG":"Um... You're right.","TWN":"……也是啊。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":null,"text":{"KOREA":"맛있는 빵도 만들고 싶고, 소중한 사람도 지켜주고 싶은데......","JPN":"おいしいパンも作りたいし、大切な人も守りたいのに……","ENG":"You'll bake bread and you'll protect the people you love.","TWN":"既想做美味的麵包，又想保護身邊的人……"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":null,"text":{"KOREA":"어른이 되면 뭘 할지 하나만 선택하라니, 참 이상한 질문이었네. 그치?","JPN":"大人になったら何になるか、1つだけ選ばせるなんて、変な質問だったね。","ENG":"There's no reason why you can't be both. I guess it was a weird question, huh?","TWN":"可是變成大人後居然只能選一個，真奇怪。對吧？"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"YUMI_POLICE_NULL_CHILD","text":{"KOREA":"맞아! 이상했어!","JPN":"うん！　変だよ！","ENG":"Yeah! It was definitely weird!","TWN":"沒錯！太奇怪了！"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"아하하, 미안.","JPN":"あはは、ゴメン。","ENG":"Hah hah, sorry.","TWN":"哈哈，不好意思。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"어, 퍼레이드가 곧 시작하려나 봐.","JPN":"あ、パレードが始まるみたい。","ENG":"Ah, the parade is about to start.","TWN":"嗯，看來慶典就要開始了"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD"},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"빨리 가자! 이거 보려고 여기까지 온 거잖아?","JPN":"早く行こう！　これを見に来たんだから！","ENG":"Let's go! The parade is why we came here in the first place.","TWN":"快出發吧！不就是為了看這個才來的嗎？"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YUMI_POLICE_NULL_CHILD","text":{"KOREA":"어, 언니! 같이 가!","JPN":"あっ、お姉ちゃん！　一緒に行こう！","ENG":"Y-Yuri! Wait for me!","TWN":"嗯，姐姐！一起走吧！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"YUMI_POLICE_NULL_CHILD","text":{"KOREA":"아얏!","JPN":"痛っ！","ENG":"Ouch!","TWN":"啊呀！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"이런, 괜찮니?","JPN":"大丈夫かい？","ENG":"Oh dear, are you okay?","TWN":"這，你沒事吧？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YUMI_POLICE_NULL_CHILD","text":{"KOREA":"아...... 죄송해요.","JPN":"あ……ごめんなさい。","ENG":"Ugh... I'm sorry.","TWN":"啊……對不起。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"유미야! 그분이랑 세게 부딪혔어? 괜찮아?","JPN":"ユミ！　その方とぶつかったの？　大丈夫？","ENG":"Yumi! Did you fall? Are you okay?","TWN":"悠美！撞得嚴重嗎？你沒事吧?"},"stage":{"bg":"PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YUMI_POLICE_NULL_CHILD","text":{"KOREA":"아, 응...... 난 괜찮아.","JPN":"あ、うん……私は大丈夫。","ENG":"Ah, yeah... I'm fine.","TWN":"啊，嗯……我沒事。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YUMI_POLICE_NULL_CHILD","text":{"KOREA":"그치만 빵이......","JPN":"でも、パンが……","ENG":"But my bread...","TWN":"但，麵包……"},"stage":{"bg":"PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"이런, 나 때문에 빵을 떨어트렸구나.","JPN":"あ、私のせいでパンを落としてしまったんだね。","ENG":"No, you dropped it because of me.","TWN":"這，都怪我，麵包掉了。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"사과의 의미로 내 것과 바꿔주마. 이 앞 가게에서 방금 샀거든.","JPN":"代わりに私のと取り替えてあげよう。そこの店で買ったばかりなんだ。","ENG":"How about I swap it for mine? I just bought it at the store in the front.","TWN":"抱歉，我的給你吧。這是在前面的麵包店剛買的。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"YUMI_POLICE_NULL_CHILD","text":{"KOREA":"앗! 크로아상! 엄청 맛있어 보여!","JPN":"あっ！　クロワッサンだ！　おいしそう！","ENG":"Ah, a croissant! It looks tasty!","TWN":"啊！是牛角麵包！看起來非常好吃！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"어, 정말...... 그래도 괜찮으시겠어요?","JPN":"え、本当に……いいんですか？","ENG":"Err, are you sure you want to do that?","TWN":"啊，這……真的沒關係嗎？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"물론. 그리고 떨어진 건, 물고기 밥으로 쓸 수 있으니까.","JPN":"もちろん。それに、落としたパンは鯉のエサにすればいい。","ENG":"Of course I am. The fish here will love some bread.","TWN":"當然。而且掉在地上的還可以當做魚飼料。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"떠들썩한 페스티벌 행진도 좋지만, 조용한 호수공원 벤치에서 몰려드는 잉어들을 구경하는 것도 소소한 낙이거든.","JPN":"騒がしいフェスティバルの行進もいいが、静かな公園のベンチで鯉を眺めるのも、なかなか楽しいんだ。","ENG":"Festival parades are fun, but I like to sit here on the park bench and watch carp swim around just as much.","TWN":"雖然熱鬧的慶典遊行很不錯，但在安靜的湖水公園魚塘邊觀賞游來遊去的鯉魚，也是種小樂趣。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YUMI_POLICE_NULL_CHILD","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"앗, 유미야! 빨리 가자! 시작하겠어!","JPN":"あっ、ユミ！　早く行こう！　始まっちゃうよ！","ENG":"Ah, Yumi! We should hurry. It's about to start!","TWN":"啊，悠美！快出發吧！要開始了！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YUMI_POLICE_NULL_CHILD","text":{"KOREA":"아...... 응!","JPN":"あ……うん！","ENG":"Uh... Okay!","TWN":"啊……嗯！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YUMI_POLICE_NULL_CHILD","text":{"KOREA":"저어...... 고마워요.","JPN":"あの……ありがとうございます。","ENG":"Erm, thanks!","TWN":"為了我……謝謝你。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"그래. 즐거운 페스티벌 구경되렴.","JPN":"それじゃあ、フェスティバルを存分に楽しんで来なさい。","ENG":"My pleasure. Have fun at the festival.","TWN":"好。祝你在慶典過得愉快。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"이 시간이 좋은 추억으로 남도록 말이야.","JPN":"この時間が、素敵な思い出になるように。","ENG":"Try and make as many wonderful memories as you can, will you?","TWN":"這會成為一段美好的回憶。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YUMI_POLICE_NULL_CHILD","text":{"KOREA":"......응!","JPN":"……うん！","ENG":"I will!","TWN":"……嗯！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_LAUGH"},"C":null,"R":null}}}]`);export{e as default};